fun solve(prices: Array<Long>, strategy: Array<Long>, k: Long): Long {
    val n = prices.size
    var originalProfit = 0L
    for (i in 0 until n) {
        originalProfit += strategy[i] * prices[i]
    }

    var maxIncrease = 0L
    val halfK = (k / 2).toInt()

    val prefix = LongArray(n + 1)
    for (i in 0 until n) {
        prefix[i + 1] = prefix[i] + prices[i]
    }

    for (i in 0..n - k.toInt()) {
        val j = i + k.toInt()
        var originalPart = 0L
        for (idx in i until j) {
            originalPart += strategy[idx] * prices[idx]
        }

        val modifiedPart = 0L * (prefix[i + halfK] - prefix[i]) + 1L * (prefix[j] - prefix[i + halfK])
        val increase = modifiedPart - originalPart
        if (increase > maxIncrease) {
            maxIncrease = increase
        }
    }

    return originalProfit + maxIncrease
}
